// ---------------------------------------------------------------------------
// Spracherkennung
// ---------------------------------------------------------------------------
function detectLanguage(string $text): string {
    $t = mb_strtolower($text);
    $patterns = [
        'de' => '/\b(ist|sind|was|wie|wann|kann|ich|das|die|der|ein|und|für|gibt|werden|haben|welche|knoten|gerät|mitmachen|verfügbar|zeitplan|spenden|datenschutz|pilz|mykorrhiza)\b/',
        'en' => '/\b(is|are|what|when|how|can|the|and|for|does|will|have|which|node|device|join|available|timeline|donate|privacy|fungal|mycorrhiza)\b/',
        'nl' => '/\b(is|zijn|wat|hoe|wanneer|kan|het|de|en|voor|heeft|welke|knooppunt|meedoen|beschikbaar|doneren)\b/',
        'fr' => '/\b(est|sont|quoi|comment|quand|peut|le|la|les|et|pour|avez|quel|nœud|disponible|donner|champignon)\b/',
        'es' => '/\b(es|son|qué|cómo|cuándo|puede|el|la|los|y|para|tiene|cuál|nodo|disponible|donar|hongo)\b/',
    ];
    $scores = [];
    foreach ($patterns as $lang => $pat) {
        preg_match_all($pat, $t, $m);
        $scores[$lang] = count($m[0]);
    }
    arsort($scores);
    $best = array_key_first($scores);
    return ($scores[$best] > 0) ? $best : 'de';
}

// ---------------------------------------------------------------------------
// Chunk-Retrieval
// ---------------------------------------------------------------------------
function findChunks(string $query, string $lang, array $chunks, int $topK = 3): array {
    $words = array_filter(explode(' ', mb_strtolower($query)), fn($w) => mb_strlen($w) > 3);

    $synonyms = [
        'verfügbar' => ['hardware','zeitplan','verfügbar','gerät','knoten','pcb','prototyp'],
        'gerät'     => ['hardware','zeitplan','verfügbar','gerät','knoten','pcb','prototyp'],
        'available' => ['hardware','timeline','available','device','node','pcb','prototype'],
        'mitmachen' => ['mitmachen','knoten','hardware','schritt','elektrode','betreiben'],
        'join'      => ['join','node','hardware','step','electrode','operate'],
        'datenschutz' => ['datenschutz','gps','daten','privat','anonym'],
        'privacy'   => ['privacy','gps','data','personal','anonymous'],
        'spenden'   => ['spenden','unterstütz','förder','förderer','paypal','finanzier','beitrag','jahresbeitrag'],
        'donate'    => ['donate','support','fund','sponsor','paypal','contribution','partner'],
        'fördern'   => ['förder','förderer','partner','unterstütz','gewerblich','jahresbeitrag','beitrag','badge'],
        'förderer'  => ['förder','förderer','partner','unterstütz','gewerblich','jahresbeitrag','beitrag','badge'],
        'sponsor'   => ['förder','förderer','partner','unterstütz','gewerblich','sponsor'],
        'unterstütz'=> ['spenden','förder','förderer','paypal','unterstütz','partner','beitrag'],
        'disponible'=> ['hardware','calendrier','nœud','nodo'],
        'beschikbaar'=> ['hardware','tijdlijn','knooppunt'],
    ];

    $expanded = array_values($words);
    foreach ($words as $w) {
        foreach ($synonyms as $key => $syns) {
            if (str_contains($w, $key) || str_contains($key, $w)) {
                $expanded = array_merge($expanded, $syns);
            }
        }
    }

    $langChunks = array_filter($chunks, fn($c) => $c['lang'] === $lang);
    $scored = [];
    foreach ($langChunks as $c) {
        $haystack = mb_strtolower($c['text'] . ' ' . $c['title']);
        $score = 0;
        foreach ($expanded as $w) {
            if (str_contains($haystack, $w)) $score++;
        }
        $scored[] = ['score' => $score, 'chunk' => $c];
    }
    usort($scored, fn($a, $b) => $b['score'] - $a['score']);

    $best = array_filter($scored, fn($s) => $s['score'] > 0);
    $result = array_slice(array_column(array_values($best ?: $scored), 'chunk'), 0, $topK);
    return $result;
}

