// ---------------------------------------------------------------------------
// Retrieval + API-Call
// ---------------------------------------------------------------------------
$lang = detectLanguage($message);
$selectedChunks = findChunks($message, $lang, $chunks);
$context = implode("\n\n", array_map(fn($c) => "[{$c['title']}]\n{$c['text']}", $selectedChunks));
$chunkTitles = array_column($selectedChunks, 'title');
$system = ($systemPrompts[$lang] ?? $systemPrompts['de']) . $context;

// Gesprächsverlauf bereinigen (max. 10 Turns)
$cleanHistory = [];
foreach (array_slice($history, -10) as $m) {
    if (in_array($m['role'] ?? '', ['user', 'assistant']) && !empty($m['content'])) {
        $cleanHistory[] = ['role' => $m['role'], 'content' => $m['content']];
    }
}
$cleanHistory[] = ['role' => 'user', 'content' => $message];

$payload = json_encode([
    'model'      => 'claude-sonnet-4-6',
    'max_tokens' => 1000,
    'system'     => $system,
    'messages'   => $cleanHistory,
], JSON_UNESCAPED_UNICODE);

$ch = curl_init('https://api.anthropic.com/v1/messages');
curl_setopt_array($ch, [
    CURLOPT_RETURNTRANSFER => true,
    CURLOPT_POST           => true,
    CURLOPT_POSTFIELDS     => $payload,
    CURLOPT_HTTPHEADER     => [
        'Content-Type: application/json',
        'anthropic-version: 2023-06-01',
        'x-api-key: ' . ANTHROPIC_API_KEY,
    ],
    CURLOPT_TIMEOUT        => 30,
]);

$response = curl_exec($ch);
$httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
curl_close($ch);

if (!$response) {
    http_response_code(502);
    echo json_encode(['error' => 'API nicht erreichbar']);
    exit;
}

$data = json_decode($response, true);

if ($httpCode !== 200 || empty($data['content'][0]['text'])) {
    http_response_code(502);
    echo json_encode(['error' => $data['error']['message'] ?? 'Unbekannter API-Fehler']);
    exit;
}

echo json_encode([
    'answer'      => $data['content'][0]['text'],
    'chunks_used' => $chunkTitles,
    'lang'        => $lang,
], JSON_UNESCAPED_UNICODE);
